import{_ as t,c as a,a1 as i,o as e}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"SNMP Enumeration sử dụng snmp_enum","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/3-enumeration/2-SNMP-Enumeration.md","filePath":"vi/categories/ethical-hacking-labs/3-enumeration/2-SNMP-Enumeration.md"}'),r={name:"vi/categories/ethical-hacking-labs/3-enumeration/2-SNMP-Enumeration.md"};function c(h,n,s,o,l,g){return e(),a("div",null,n[0]||(n[0]=[i(`<h1 id="snmp-enumeration-su-dung-snmp-enum" tabindex="-1">SNMP Enumeration sử dụng <code>snmp_enum</code> <a class="header-anchor" href="#snmp-enumeration-su-dung-snmp-enum" aria-label="Permalink to &quot;SNMP Enumeration sử dụng \`snmp_enum\`&quot;">​</a></h1><p>Module <strong>snmp_enum</strong> trong Metasploit cho phép enumerate bất kỳ thiết bị nào hỗ trợ giao thức SNMP. Nó hỗ trợ thông tin phần cứng, phần mềm và mạng. Community string mặc định được sử dụng là &#39;public&#39;.</p><p>SNMP enumeration là quá trình enumerate các tài khoản người dùng và thiết bị trên máy tính có bật SNMP.</p><p>Dịch vụ SNMP đi kèm với hai mật khẩu, được sử dụng để cấu hình và truy cập SNMP agent từ trạm quản lý. Chúng là: Read community string và Read/Write community string. Các chuỗi (mật khẩu) này có giá trị mặc định, giống nhau trên tất cả các hệ thống. Chúng trở thành điểm xâm nhập dễ dàng cho kẻ tấn công nếu quản trị viên không thay đổi.</p><p>Kẻ tấn công enumerate SNMP để trích xuất thông tin về tài nguyên mạng như hosts, routers, thiết bị, shares(...) Thông tin mạng như bảng ARP, bảng định tuyến, thông tin cụ thể của thiết bị và thống kê lưu lượng.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><p>Enumeration:</p><ul><li>Các thiết bị đã kết nối</li><li>Tên host và thông tin</li><li>Miền (Domain)</li><li>Thông tin phần cứng và lưu trữ</li><li>Các thành phần phần mềm</li><li>Tổng bộ nhớ</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy Kali Linux (Kẻ tấn công)</li><li>Windows Server 2012 / 2016 (Nạn nhân/Mục tiêu)</li><li>Ubuntu <a href="https://www.vulnhub.com/entry/bwapp-bee-box-v16,53/" target="_blank" rel="noreferrer">BeeBox</a> (Nạn nhân/Mục tiêu)</li></ul><h2 id="kiem-tra-trang-thai-cong-snmp" tabindex="-1">Kiểm tra Trạng thái Cổng SNMP <a class="header-anchor" href="#kiem-tra-trang-thai-cong-snmp" aria-label="Permalink to &quot;Kiểm tra Trạng thái Cổng SNMP&quot;">​</a></h2><p>Đầu tiên chúng ta cần tìm hiểu xem cổng SNMP có mở hay không. <strong>SNMP sử dụng cổng 161 theo mặc định</strong>. Để kiểm tra thông tin này, trước tiên chúng ta cần chạy quét cổng Nmap.</p><p><strong>Lưu ý</strong>: Nhớ kích hoạt dịch vụ SNMP trên Windows Server của bạn.</p><p><code>-sU</code>: Quét cổng UDP. <code>-p</code>: Phạm vi quét cổng.</p><p><code>nmap -sU -p 161 &lt;Target IP Address&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.38</span></span>
<span class="line"><span>Host is up (0.00070s latency).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PORT    STATE SERVICE</span></span>
<span class="line"><span>161/udp open  snmp</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span></code></pre></div><h2 id="enumerate-community-string" tabindex="-1">Enumerate Community String <a class="header-anchor" href="#enumerate-community-string" aria-label="Permalink to &quot;Enumerate Community String&quot;">​</a></h2><p>Để thực hiện SNMP enumeration, bạn có nhiều công cụ có sẵn. Hướng dẫn này trình bày hai cách để thực hiện cùng một việc: sử dụng <strong>Metasploit</strong> và <strong>snmp-check</strong>.</p><p>Trên Metasploit, bạn có thể sử dụng module <strong>snmp_enum</strong>:</p><p><code>auxiliary/scanner/snmp/snmp_enum</code></p><p>Cách khác là sử dụng snmp-check. snmp-check là một gói có sẵn trên Kali Linux, chỉ cần mở terminal và gõ:</p><p><code>snmp-check &lt;Target IP Address&gt;</code></p><p>Cả hai phương pháp đều enumerate thông tin máy mục tiêu và trả về cùng một <strong>danh sách toàn diện</strong> hiển thị <strong>Thông tin Hệ thống</strong>. Các công cụ này hỗ trợ các enumerate sau:</p><ul><li>Địa chỉ IP của Host</li><li>Tên host</li><li>Mô tả phần cứng</li><li>Thời gian hoạt động của hệ thống</li><li>Thời gian hoạt động SNMP</li><li>Miền nếu hệ thống được kết nối trong Domain</li><li>Tài khoản người dùng</li><li>Địa chỉ MAC</li><li>Các tiến trình đang chạy</li><li><a href="https://tools.kali.org/information-gathering/snmp-check" target="_blank" rel="noreferrer">Và nhiều hơn nữa</a></li></ul>`,24)]))}const p=t(r,[["render",c]]);export{m as __pageData,p as default};
